-- Trajectory pause markers + on-device gait state on IMU samples.
--
-- NOTE: hand-edited to NOT drop "TrajectorySession_buildingId_fkey". The
-- buildingId→Building FK is enforced in raw SQL (the Prisma schema models
-- buildingId as a plain String on purpose), so `migrate dev` flags it as drift
-- and tries to drop it. Dropping it would silently remove referential
-- integrity, so that autogenerated DROP CONSTRAINT was removed. Idempotent
-- guards mirror the add_trajectory_collection migration's convention.

-- AlterTable: on-device gait-detector state at each IMU sample (all nullable).
ALTER TABLE "TrajectoryImuSample"
  ADD COLUMN IF NOT EXISTS "vertAccel" DOUBLE PRECISION,
  ADD COLUMN IF NOT EXISTS "gaitVerticality" DOUBLE PRECISION,
  ADD COLUMN IF NOT EXISTS "gaitEnergy" DOUBLE PRECISION,
  ADD COLUMN IF NOT EXISTS "gaitIsWalking" BOOLEAN,
  ADD COLUMN IF NOT EXISTS "gaitAmplitude" DOUBLE PRECISION;

-- CreateTable: a stationary pause marked mid-walk (holds the ground-truth label).
CREATE TABLE IF NOT EXISTS "TrajectoryPauseEvent" (
    "id" TEXT NOT NULL,
    "walkId" TEXT NOT NULL,
    "seq" INTEGER NOT NULL,
    "pauseTMs" DOUBLE PRECISION NOT NULL,
    "resumeTMs" DOUBLE PRECISION,

    CONSTRAINT "TrajectoryPauseEvent_pkey" PRIMARY KEY ("id")
);

-- CreateIndex
CREATE INDEX IF NOT EXISTS "TrajectoryPauseEvent_walkId_seq_idx"
  ON "TrajectoryPauseEvent"("walkId", "seq");

-- AddForeignKey
ALTER TABLE "TrajectoryPauseEvent"
  ADD CONSTRAINT "TrajectoryPauseEvent_walkId_fkey"
  FOREIGN KEY ("walkId") REFERENCES "TrajectoryWalk"("id")
  ON DELETE CASCADE ON UPDATE CASCADE;
